import React from 'react';
import { Routes, Route, BrowserRouter } from "react-router-dom";  // eslint-disable-next-line
import { Outlet, Link } from 'react-router-dom';
// import logo from './logo.svg';
import './App.css';
import Register from './register';  // eslint-disable-next-line
import EmailCheck from "./emailcheck";  // eslint-disable-next-line

const App = () => {
  return (
    <BrowserRouter>
      <div class="App">
        {/* 標頭 */}
        <nav class="menu">
          <ul class="subMenu">
            <li class="mainLink"><a href="https://www.vscinemas.com.tw/vsweb/#" class="firstMenu">影城介紹</a>
              <ul class="sublink">
                <li><a href="https://www.vscinemas.com.tw/vsweb/theater/index.aspx">威秀影城</a></li>
                <li><a href="https://www.vscinemas.com.tw/vsweb/theater/detail2.aspx?id=23">MOVIE</a></li>
              </ul>
            </li>
          </ul>
        </nav>


        <Routes>
          <Route path='/' element={<App />}>
            <Route path="/emailcheck" element={<EmailCheck />} />
            <Route path="/register" element={<Register />} />
          </Route>
        </Routes>


      </div>
      </BrowserRouter>
  );
}

export default App;
